INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-4c199b1b-moex-00003', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲與乙為同一棟社區之住戶，甲住8樓，乙住7樓，甲生性愛熱鬧，常常邀約親朋好友到家作客， 並大聲喧嘩，甚至已半夜時分仍在家中高歌作樂。下列敘述，何者錯誤？', '["在他人居住區域，發出超越一般人社會生活所能忍受之噪音，屬不法侵害他人居住安寧之人格 利益", "人格利益至高無上，不容侵犯，只要遭受侵害，不問程度如何，被害人均得依民法第195條第 1項有關人格及身分法益侵害規定，請求賠償相當之金額", "如果長期、持續性噪音，已使人因此無法入眠，健康受損，可能構成健康權之侵害", "健康權屬於特別人格權，若受侵害，被害人得請求非財產上之金錢賠償 23520"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00004', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲將A地出賣於乙，並辦理所有權移轉登記。下列關於所有權移轉之敘述，何者錯誤？', '["應以書面為之", "非經登記，不生效力", "非經移轉占有，不生效力", "此移轉行為係法律行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00005', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '父親甲贈與未成年子女乙一棟房屋，由甲代理乙受領，其效力如何？', '["無效", "有效", "效力未定", "得撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00006', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '民法中關於權利主體「自然人」之規定，下列敘述，何者正確？', '["某藝人以「小香瓜」為藝名，因其非真名，不受民法有關姓名權規定之保護", "甲與乙同時遇難，不能證明死亡先後時，視為同時死亡", "丙因失蹤多時生死不明，被妻子依法聲請法院宣告其死亡。但丙實則仍生存中，卻因已受死亡 宣告，所以權利能力及行為能力均為消滅", "丁開車闖紅燈撞上正在過馬路之孕婦戊，致其胎兒受傷。戊為胎兒之法定代理人，固得代為受 領丁給付之賠償金，但若嗣後胎兒死產，該受領之賠償金應返還丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00007', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲依民法規定發起設立A學術性社團法人，並將其主事務所設於臺中市。依民法規定，A法人應 向何主管機關登記，始得成立？', '["臺中市政府", "臺中地方法院", "內政部", "教育部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00008', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲80歲，罹輕度失智症，配偶已歿，有子女乙、丙、丁，平日由女兒乙照顧，乙擔心甲因心智缺 陷，而面臨不必要之法律糾紛，遂向法院聲請為甲為輔助宣告，法院經審查對甲為輔助宣告，並 以乙為甲之輔助人。下列甲之行為，何者須先取得輔助人乙之同意？', '["甲與好友相約到餐廳吃飯", "甲在好友A、B偕同下到C公證人處，在A、B、C見證下自書遺囑，就其法定繼承人乙、丙、 丁為遺產分配各得1/2、1/4、1/4", "甲因開車造成D受傷，自行與D成立和解契約，願意理賠D之身體傷害新臺幣（下同）50萬元", "甲自行到某百貨公司購買價錢1萬元之手錶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00009', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '下列關於最高限額抵押權之敘述，何者錯誤？', '["債務人或第三人提供其不動產為擔保", "得擔保不確定或概括債權，例如約定擔保債權人與債務人間「現在及將來一切債務及其利息、 遲延利息、違約金、實行抵押權費用」", "得擔保一定範圍內之不特定債權", "所擔保之債權，應受最高額度限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00010', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '受有概括委任之受任人，為下列何種行為，不須有委任人之特別授權？', '["設定土地之普通抵押權", "贈與動產", "訂立二年之房屋租約", "訂立和解契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00011', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲將其所有之A屋出租於乙後，乙將其對A屋之租賃權讓與丙，並通知甲該情事。下列敘述，何 者正確？', '["如甲、乙間並無禁止轉讓之特約，乙之租賃權性質上並非不得讓與之債權", "如乙未能取得甲之同意移轉租賃權時，乙對丙應負債務不履行責任", "丙得以已通知甲關於A屋租賃權之讓與事實，主張其受讓對甲發生效力", "乙、丙就使用A屋而應給付與甲之租金，負連帶責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00012', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-114-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲請乙大幅翻修其房屋，約定由甲供給材料，乙為其施作，完工後給付報酬若干。乙明知甲所提 供之材料有問題，足以發生重大瑕疵，卻故意不告知甲，又以特約免除乙修繕房屋之瑕疵擔保義 務。乙嗣於民國（下同）103年1月5日完工，甲於112年4月20日始發現瑕疵，旋即通知乙， 並於113年5月1日定相當期限訴請乙修補瑕疵。對此，乙主張其不負物之瑕疵擔保義務，甲又 已罹於瑕疵發見期間，甲並已逾越權利行使期間等語，以資抗辯。下列敘述，何者正確？', '["因有問題之材料，係由甲所提供，故甲無定相當期限請求乙修補瑕疵之權利", "免除乙修繕房屋之瑕疵擔保義務之特約，為有效", "甲發現瑕疵時，已罹於5年之瑕疵發見期間，故甲不得主張定相當期限請求乙修補瑕疵之權利", "乙提出甲訴請乙修補瑕疵已逾越權利行使期間之抗辯，屬有理由 23520"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "7894a239bcc1", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "235", "s": "0904", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL)
